import{_ as e,o as a,c as l,a3 as o}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"会话变量系统 (Session Variables)","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/macro-system/session-variables.md","filePath":"user-guide/tools/llm-chat/macro-system/session-variables.md","lastUpdated":1778244893000}'),s={name:"user-guide/tools/llm-chat/macro-system/session-variables.md"};function r(i,t,n,d,h,g){return a(),l("div",null,[...t[0]||(t[0]=[o('<div><h1 id="会话变量系统-session-variables" tabindex="-1">会话变量系统 (Session Variables) <a class="header-anchor" href="#会话变量系统-session-variables" aria-label="Permalink to &quot;会话变量系统 (Session Variables)&quot;">​</a></h1><p>除了宏系统提供的临时变量外，LLM Chat 还支持一套持久化的<strong>会话变量 (Session Variables)</strong> 系统。它允许你定义复杂的数值或状态（如 RPG 游戏中的“生命值”、“金钱”、“好感度”），并自动追踪其变化历史。</p><h2 id="_1-核心特性" tabindex="-1">1. 核心特性 <a class="header-anchor" href="#_1-核心特性" aria-label="Permalink to &quot;1. 核心特性&quot;">​</a></h2><ul><li><strong>持久化</strong>: 变量值存储在数据库中，跨消息轮次和应用重启依然有效。</li><li><strong>快照机制</strong>: 每一条消息发送时，系统都会记录下当时的变量状态快照。</li><li><strong>可视化</strong>: 支持在聊天界面中以进度条、数值等形式展示变量。</li><li><strong>宏联动</strong>: 可以在提示词中通过 <code>{{var_name}}</code> 引用，或通过特定宏进行修改。</li></ul><h2 id="_2-配置变量树" tabindex="-1">2. 配置变量树 <a class="header-anchor" href="#_2-配置变量树" aria-label="Permalink to &quot;2. 配置变量树&quot;">​</a></h2><p>在 <strong>Agent 编辑器 -&gt; 会话变量 (Variables)</strong> 面板中进行配置：</p><ol><li><strong>启用变量系统</strong>: 开启总开关。</li><li><strong>定义变量</strong>: <ul><li><strong>名称</strong>: 变量的唯一 ID。</li><li><strong>显示名称</strong>: UI 中展示的标签。</li><li><strong>初始值</strong>: 变量的起始数值或文本。</li><li><strong>范围约束</strong>: 可选。设置最小值和最大值（如生命值 0~100）。</li></ul></li><li><strong>组织结构</strong>: 支持创建分组，将相关变量组织在一起（如“基础属性”、“技能等级”）。</li></ol><h2 id="_3-运行与交互" tabindex="-1">3. 运行与交互 <a class="header-anchor" href="#_3-运行与交互" aria-label="Permalink to &quot;3. 运行与交互&quot;">​</a></h2><h3 id="变量快照-snapshot" tabindex="-1">变量快照 (Snapshot) <a class="header-anchor" href="#变量快照-snapshot" aria-label="Permalink to &quot;变量快照 (Snapshot)&quot;">​</a></h3><p>每当 LLM 生成回复或用户发送消息后，系统会自动保存当前的变量状态。</p><ul><li><strong>查看历史</strong>: 在<a href="./../context-pipeline/analyzer">上下文分析器</a>中，你可以选择任意历史消息，查看该时刻的变量数值。</li><li><strong>回滚感应</strong>: 当你删除消息或从历史节点重新开始分支时，变量值会自动恢复到该节点对应的快照状态。</li></ul><h3 id="ui-展示" tabindex="-1">UI 展示 <a class="header-anchor" href="#ui-展示" aria-label="Permalink to &quot;UI 展示&quot;">​</a></h3><p>如果配置了 UI 样式，变量会显示在聊天界面的侧边栏或消息上方，实时反馈状态变化。</p><h2 id="_4-变量操作宏" tabindex="-1">4. 变量操作宏 <a class="header-anchor" href="#_4-变量操作宏" aria-label="Permalink to &quot;4. 变量操作宏&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">生命周期</th><th style="text-align:left;">宏名称</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>局部 (单次请求)</strong></td><td style="text-align:left;"><code>{{setvar}}</code> / <code>{{getvar}}</code></td><td style="text-align:left;">仅在本次 Prompt 组装过程中有效，用于跨预设消息传递中间状态。</td></tr><tr><td style="text-align:left;"><strong>持久 (会话级)</strong></td><td style="text-align:left;"><code>{{set_session_var}}</code></td><td style="text-align:left;">直接修改数据库中的会话变量值。</td></tr><tr><td style="text-align:left;"><strong>全局 (进程级)</strong></td><td style="text-align:left;"><code>{{setglobalvar}}</code></td><td style="text-align:left;">在整个应用运行期间有效，不随会话切换而改变。</td></tr></tbody></table><h2 id="_5-最佳实践-rpg-属性系统" tabindex="-1">5. 最佳实践：RPG 属性系统 <a class="header-anchor" href="#_5-最佳实践-rpg-属性系统" aria-label="Permalink to &quot;5. 最佳实践：RPG 属性系统&quot;">​</a></h2><ol><li><strong>定义变量</strong>: 创建 <code>hp</code> (初始 100), <code>gold</code> (初始 0)。</li><li><strong>提示词注入</strong>: 在系统提示词中加入：<code>当前状态：生命值 {{hp}}, 金币 {{gold}}。</code></li><li><strong>动态修改</strong>: 在快捷操作或正则管道中，根据 LLM 的输出（如“你受到了 10 点伤害”）触发 <code>{{decvar::hp::10}}</code>。</li></ol><hr><h3 id="相关阅读" tabindex="-1">相关阅读 <a class="header-anchor" href="#相关阅读" aria-label="Permalink to &quot;相关阅读&quot;">​</a></h3><ul><li><a href="./macro-reference">宏参考手册</a></li><li><a href="./../context-pipeline/analyzer">上下文分析器</a></li><li><a href="./../agents/editor-guide">Agent 基础设定</a></li></ul></div>',1)])])}const b=e(s,[["render",r]]);export{u as __pageData,b as default};
